196	static void rime_candidate_copy(RimeCandidate* dest, const an<Candidate>& src) {
197	  dest->text = new char[src->text().length() + 1];
198	  std::strcpy(dest->text, src->text().c_str());
199	  string comment(src->comment());
200	  if (!comment.empty()) {
201	    dest->comment = new char[comment.length() + 1];
202	    std::strcpy(dest->comment, comment.c_str());
203	  } else {
204	    dest->comment = nullptr;
205	  }
206	  dest->reserved = nullptr;
207	}
