209	RIME_DEPRECATED Bool RimeGetContext(RimeSessionId session_id,
210	                                    RIME_FLAVORED(RimeContext) * context) {
211	  if (!context || context->data_size <= 0)
212	    return False;
213	  RIME_STRUCT_CLEAR(*context);
214	  an<Session> session(Service::instance().GetSession(session_id));
215	  if (!session)
216	    return False;
217	  Context* ctx = session->context();
218	  if (!ctx)
219	    return False;
220	  if (ctx->IsComposing()) {
221	    Preedit preedit = ctx->GetPreedit();
222	    context->composition.length = preedit.text.length();
223	    context->composition.preedit = new char[preedit.text.length() + 1];
224	    std::strcpy(context->composition.preedit, preedit.text.c_str());
225	    context->composition.cursor_pos = preedit.caret_pos;
226	    context->composition.sel_start = preedit.sel_start;
227	    context->composition.sel_end = preedit.sel_end;
228	    if (RIME_STRUCT_HAS_MEMBER(*context, context->commit_text_preview)) {
229	      string commit_text(ctx->GetCommitText());
230	      if (!commit_text.empty()) {
231	        context->commit_text_preview = new char[commit_text.length() + 1];
232	        std::strcpy(context->commit_text_preview, commit_text.c_str());
233	      }
234	    }
235	  }
236	  if (ctx->HasMenu()) {
237	    Segment& seg(ctx->composition().back());
238	    int page_size = 5;
239	    Schema* schema = session->schema();
240	    if (schema)
241	      page_size = schema->page_size();
242	    int selected_index = seg.selected_index;
243	    int page_no = selected_index / page_size;
244	    the<Page> page(seg.menu->CreatePage(page_size, page_no));
245	    if (page) {
246	      context->menu.page_size = page_size;
247	      context->menu.page_no = page_no;
248	      context->menu.is_last_page = Bool(page->is_last_page);
249	      context->menu.highlighted_candidate_index = selected_index % page_size;
250	      int i = 0;
251	      context->menu.num_candidates = page->candidates.size();
252	      if (ctx->get_option("_hide_candidate")) {
253	        context->menu.num_candidates = 0;
254	        return True;
255	      }
256	      context->menu.candidates = new RimeCandidate[page->candidates.size()];
257	      for (const an<Candidate>& cand : page->candidates) {
258	        RimeCandidate* dest = &context->menu.candidates[i++];
259	        rime_candidate_copy(dest, cand);
260	      }
261	      if (schema) {
262	        const string& select_keys(schema->select_keys());
263	        if (!select_keys.empty()) {
264	          context->menu.select_keys = new char[select_keys.length() + 1];
265	          std::strcpy(context->menu.select_keys, select_keys.c_str());
266	        }
267	        Config* config = schema->config();
268	        an<ConfigList> select_labels =
269	            config->GetList("menu/alternative_select_labels");
270	        if (select_labels && (size_t)page_size <= select_labels->size()) {
271	          context->select_labels = new char*[page_size];
272	          for (size_t i = 0; i < (size_t)page_size; ++i) {
273	            an<ConfigValue> value = select_labels->GetValueAt(i);
274	            string label = value->str();
275	            context->select_labels[i] = new char[label.length() + 1];
276	            std::strcpy(context->select_labels[i], label.c_str());
277	          }
278	        }
279	      }
280	    }
281	  }
282	  return True;
283	}
