476	  if (!output)
477	    return False;
478	  output->size = 0;
479	  output->list = NULL;
480	  Schema default_schema;
481	  Config* config = default_schema.config();
482	  if (!config)
483	    return False;
484	  an<ConfigList> schema_list = config->GetList("schema_list");
485	  if (!schema_list || schema_list->size() == 0)
486	    return False;
487	  output->list = new RimeSchemaListItem[schema_list->size()];
488	  for (size_t i = 0; i < schema_list->size(); ++i) {
489	    an<ConfigMap> item = As<ConfigMap>(schema_list->GetAt(i));
490	    if (!item)
491	      continue;
492	    an<ConfigValue> schema_property = item->GetValue("schema");
493	    if (!schema_property)
494	      continue;
495	    const string& schema_id(schema_property->str());
496	    RimeSchemaListItem& x(output->list[output->size]);
497	    x.schema_id = new char[schema_id.length() + 1];
498	    strcpy(x.schema_id, schema_id.c_str());
499	    Schema schema(schema_id);
500	    x.name = new char[schema.schema_name().length() + 1];
501	    strcpy(x.name, schema.schema_name().c_str());
502	    x.reserved = NULL;
503	    ++output->size;
504	  }
505	  if (output->size == 0) {
506	    delete[] output->list;
507	    output->list = NULL;
