662	template <class T>
663	struct RimeConfigIteratorImpl {
664	  typename T::Iterator iter;
665	  typename T::Iterator end;
666	  string prefix;
667	  string key;
668	  string path;
669	  RimeConfigIteratorImpl<T>(T& container, const string& root_path)
670	      : iter(container.begin()), end(container.end()) {
671	    if (root_path.empty() || root_path == "/") {
672	      // prefix is empty
673	    } else {
674	      prefix = root_path + "/";
675	    }
676	  }
677	};
