679	RIME_DEPRECATED Bool RimeConfigBeginList(RimeConfigIterator* iterator,
680	                                         RimeConfig* config,
681	                                         const char* key) {
682	  if (!iterator || !config || !key)
683	    return False;
684	  iterator->list = NULL;
685	  iterator->map = NULL;
686	  iterator->index = -1;
687	  iterator->key = NULL;
688	  iterator->path = NULL;
689	  Config* c = reinterpret_cast<Config*>(config->ptr);
690	  if (!c)
691	    return False;
692	  an<ConfigList> list = c->GetList(key);
693	  if (!list)
694	    return False;
695	  iterator->list = new RimeConfigIteratorImpl<ConfigList>(*list, key);
696	  return True;
697	}
