699	RIME_DEPRECATED Bool RimeConfigBeginMap(RimeConfigIterator* iterator,
700	                                        RimeConfig* config,
701	                                        const char* key) {
702	  if (!iterator || !config || !key)
703	    return False;
704	  iterator->list = NULL;
705	  iterator->map = NULL;
706	  iterator->index = -1;
707	  iterator->key = NULL;
708	  iterator->path = NULL;
709	  Config* c = reinterpret_cast<Config*>(config->ptr);
710	  if (!c)
711	    return False;
712	  an<ConfigMap> m = c->GetMap(key);
713	  if (!m)
714	    return False;
715	  iterator->map = new RimeConfigIteratorImpl<ConfigMap>(*m, key);
716	  return True;
717	}
718	
719	RIME_DEPRECATED Bool RimeConfigNext(RimeConfigIterator* iterator) {
720	  if (!iterator->list && !iterator->map)
721	    return False;
722	  if (iterator->list) {
723	    RimeConfigIteratorImpl<ConfigList>* p =
724	        reinterpret_cast<RimeConfigIteratorImpl<ConfigList>*>(iterator->list);
725	    if (!p)
726	      return False;
727	    if (++iterator->index > 0)
728	      ++p->iter;
729	    if (p->iter == p->end)
730	      return False;
731	    std::ostringstream key;
732	    key << "@" << iterator->index;
733	    p->key = key.str();
734	    p->path = p->prefix + p->key;
735	    iterator->key = p->key.c_str();
736	    iterator->path = p->path.c_str();
737	    return True;
738	  }
739	  if (iterator->map) {
740	    RimeConfigIteratorImpl<ConfigMap>* p =
741	        reinterpret_cast<RimeConfigIteratorImpl<ConfigMap>*>(iterator->map);
742	    if (!p)
743	      return False;
744	    if (++iterator->index > 0)
745	      ++p->iter;
746	    if (p->iter == p->end)
747	      return False;
748	    p->key = p->iter->first;
749	    p->path = p->prefix + p->key;
750	    iterator->key = p->key.c_str();
751	    iterator->path = p->path.c_str();
752	    return True;
753	  }
754	  return False;
755	}
756	
757	RIME_DEPRECATED void RimeConfigEnd(RimeConfigIterator* iterator) {
758	  if (!iterator)
759	    return;
760	  if (iterator->list)
761	    delete reinterpret_cast<RimeConfigIteratorImpl<ConfigList>*>(
762	        iterator->list);
763	  if (iterator->map)
764	    delete reinterpret_cast<RimeConfigIteratorImpl<ConfigMap>*>(iterator->map);
765	  memset(iterator, 0, sizeof(RimeConfigIterator));
766	}
