986	static bool do_with_candidate_on_current_page(
987	    RimeSessionId session_id,
988	    size_t index,
989	    bool (Context::*verb)(size_t index)) {
990	  an<Session> session(Service::instance().GetSession(session_id));
991	  if (!session)
992	    return false;
993	  Context* ctx = session->context();
994	  if (!ctx || !ctx->HasMenu())
995	    return false;
996	  Schema* schema = session->schema();
997	  if (!schema)
998	    return false;
999	  size_t page_size = (size_t)schema->page_size();
1000	  if (index >= page_size)
1001	    return false;
1002	  const auto& seg(ctx->composition().back());
1003	  size_t page_start = seg.selected_index / page_size * page_size;
1004	  return (ctx->*verb)(page_start + index);
1005	}
