1007	static Bool RimeChangePage(RimeSessionId session_id, Bool backward) {
1008	  an<Session> session(Service::instance().GetSession(session_id));
1009	  if (!session)
1010	    return False;
1011	  Context* ctx = session->context();
1012	  if (!ctx || !ctx->HasMenu())
1013	    return False;
1014	  Schema* schema = session->schema();
1015	  if (!schema)
1016	    return False;
1017	  size_t page_size = (size_t)schema->page_size();
1018	  auto& seg(ctx->composition().back());
1019	  size_t current_index = seg.selected_index;
1020	  size_t index =
1021	      backward ? (current_index <= page_size ? 0 : current_index - page_size)
1022	               : (current_index + page_size);
1023	  DLOG(INFO) << "current selection: " << current_index << ", flipping "
1024	             << (backward ? "backward" : "forward") << ", new selection "
1025	             << index;
1026	  seg.tags.insert("paging");
1027	  return Bool(ctx->Highlight(index));
1028	}
